args.sparql:
SELECT ?character ?characterLabel WHERE {
  wd:Q191441 wdt:P161 wd:Q11571 .
  wd:Q191441 p:P161/ps:P161 wd:Q11571 ;
             p:P161/pq:P1237 ?character .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT ?character ?characterLabel WHERE {
  wd:Q191441 p:P161 ?statement .
  ?statement ps:P161 wd:Q83338 ;
             pq:P451 ?character .
  ?character rdfs:label ?characterLabel .
  FILTER(lang(?characterLabel) = "en")
}

SELECT ?role ?roleLabel WHERE {
  wd:Q83338 p:P161 ?statement .
  ?statement ps:P161 ?production .
  ?production wdt:P144 wd:Q19871 .
  OPTIONAL { ?statement pq:P451 ?role . }
  ?role rdfs:label ?roleLabel .
  FILTER(LANG(?roleLabel) = "en")
}

SELECT ?role ?roleLabel WHERE {
  ?production wdt:P144 wd:Q19871 .
  ?production p:P161 ?statement .
  ?statement ps:P161 wd:Q83338 ;
             pq:P451 ?role .
  ?role rdfs:label ?roleLabel .
  FILTER(LANG(?roleLabel) = "en")
}
